import{_ as t,a as n,b as e,c as i}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as o,o as l,c as r,a2 as h}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Other/magnet-transfer.md","filePath":"vi-VN/Other/magnet-transfer.md","lastUpdated":1781962217000}'),d={name:"vi-VN/Other/magnet-transfer.md"};function c(s,a,g,u,p,m){return l(),r("div",null,[...a[0]||(a[0]=[h('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer tải files từ magnet link và tự động upload chúng lên cloud storage channel bạn chọn.</p><p>Tính năng này hữu ích khi chuyển anime episodes, videos, archives và các files tương tự. Paste magnet link, ImgBed tạo background download task. Sau khi download xong, file được upload vào ImgBed và final link xuất hiện trong upload list.</p><p><img src="'+t+'" alt="Magnet transfer" loading="lazy"></p><h2 id="dung-o-đau" tabindex="-1">Dùng ở đâu <a class="header-anchor" href="#dung-o-đau" aria-label="Permalink to &quot;Dùng ở đâu&quot;">​</a></h2><p>Magnet transfer entry nằm trong homepage upload area.</p><p>Paste magnet link vào input box, chọn <code>Transfer</code>, rồi upload.</p><p><img src="'+n+'" alt="Upload anime" loading="lazy"></p><h2 id="truoc-lan-dung-đau-tien" tabindex="-1">Trước lần dùng đầu tiên <a class="header-anchor" href="#truoc-lan-dung-đau-tien" aria-label="Permalink to &quot;Trước lần dùng đầu tiên&quot;">​</a></h2><p>Trước tiên cần cấu hình magnet transfer trong admin panel.</p><p>Thường bạn cần:</p><ol><li>GitHub account để chạy download task.</li><li>Cloud upload channel, ví dụ Google Drive hoặc OneDrive.</li><li>Target upload directory.</li><li>Task timeout.</li></ol><p>Khi settings đã sẵn sàng, quay lại homepage và paste magnet link để bắt đầu transfer.</p><h2 id="upload-magnet-link" tabindex="-1">Upload Magnet Link <a class="header-anchor" href="#upload-magnet-link" aria-label="Permalink to &quot;Upload Magnet Link&quot;">​</a></h2><ol><li>Paste magnet link vào homepage upload box.</li><li>Đảm bảo mode được đặt là <code>Transfer</code>.</li><li>Nhấn upload.</li><li>Chờ ImgBed tạo magnet task.</li><li>Sau khi task bắt đầu, dùng floating panel <code>Magnet Tasks</code> ở góc dưới bên phải để xem progress.</li></ol><p>Download và upload có thể mất thời gian. Speed phụ thuộc vào magnet resource, GitHub runtime environment và selected cloud storage channel.</p><p><img src="'+e+'" alt="Magnet downloading" loading="lazy"></p><h2 id="sau-khi-hoan-tat" tabindex="-1">Sau khi hoàn tất <a class="header-anchor" href="#sau-khi-hoan-tat" aria-label="Permalink to &quot;Sau khi hoàn tất&quot;">​</a></h2><p>Khi task hoàn tất, upload list hiển thị file name và link.</p><p>Videos hiển thị video preview, images hiển thị image preview, và other files hiển thị regular file icon.</p><p><img src="'+i+'" alt="Downloaded video" loading="lazy"></p><p>Bạn có thể copy:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>Direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts hoặc notes</td></tr><tr><td>HTML</td><td>Web page code</td></tr><tr><td>BBCode</td><td>Forums hỗ trợ BBCode</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>Magnet task panel ở góc dưới bên phải hiển thị task count, task name, progress và final status.</p><p>Common states:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>Task đã được tạo và đang chờ chạy.</td></tr><tr><td>Downloading</td><td>Magnet resource đang được download.</td></tr><tr><td>Uploading</td><td>File đã download xong và đang upload lên cloud storage.</td></tr><tr><td>Completed</td><td>Upload thành công và link có thể copy.</td></tr><tr><td>Failed</td><td>Task không hoàn tất thành công. Kiểm tra message rồi thử lại.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Nếu magnet link chứa nhiều files, ImgBed ưu tiên main completed file để hiển thị.</li><li>Large files mất nhiều thời gian hơn. Hãy chờ task finish trước khi refresh page.</li><li>Nếu magnet resource không có available peers, download có thể rất chậm hoặc fail.</li><li>Nếu cloud account hết quota, authorization hết hạn hoặc upload directory sai, task có thể fail.</li><li>Video preview có thể cần vài giây sau khi upload complete.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="paste-magnet-link-roi-nhung-khong-co-gi-bat-đau" tabindex="-1">Paste Magnet Link rồi nhưng không có gì bắt đầu <a class="header-anchor" href="#paste-magnet-link-roi-nhung-khong-co-gi-bat-đau" aria-label="Permalink to &quot;Paste Magnet Link rồi nhưng không có gì bắt đầu&quot;">​</a></h3><p>Xác nhận magnet transfer đã enabled trong admin panel và đã chọn GitHub account cùng cloud channel dùng được.</p><h3 id="download-luon-cham" tabindex="-1">Download luôn chậm <a class="header-anchor" href="#download-luon-cham" aria-label="Permalink to &quot;Download luôn chậm&quot;">​</a></h3><p>Magnet speed phụ thuộc vào chính resource. Nếu không có available peers, download có thể rất chậm hoặc không thể tải.</p><h3 id="upload-xong-nhung-khong-co-preview" tabindex="-1">Upload xong nhưng không có Preview <a class="header-anchor" href="#upload-xong-nhung-khong-co-preview" aria-label="Permalink to &quot;Upload xong nhưng không có Preview&quot;">​</a></h3><p>Trước tiên xác nhận file link mở được. Video files có thể cần một chút thời gian để load trong browser, hoặc bạn có thể mở link trực tiếp.</p><h3 id="task-fail-thi-can-kiem-tra-gi" tabindex="-1">Task fail thì cần kiểm tra gì? <a class="header-anchor" href="#task-fail-thi-can-kiem-tra-gi" aria-label="Permalink to &quot;Task fail thì cần kiểm tra gì?&quot;">​</a></h3><p>Kiểm tra magnet link có valid không, cloud channel có hoạt động không và upload directory có đúng không. Sau đó submit task lại.</p>',38)])])}const v=o(d,[["render",c]]);export{b as __pageData,v as default};
